30â†’    switch (activeTab) {
31â†’      case 'run':
32â†’        return <Dashboard user={user} />;
33â†’      case 'report':
34â†’        return <ReportsPanel user={user} />;
35â†’      case 'mechanic':
36â†’        return <MechanicPanel user={user} />;
37â†’      case 'admin':
38â†’        return <AdminPanel user={user} />;
