54â†’        <Route path="/*" element={
55â†’          user ? (
56â†’            <div className="app-container">
57â†’              <Sidebar user={user} activeTab={activeTab} onTabChange={setActiveTab} onLogout={handleLogout} />
58â†’              <div className="main-content">
59â†’                {renderContent()}
60â†’              </div>
61â†’            </div>
62â†’          ) : (
63â†’            <Navigate to="/login" />
64â†’          )
65â†’        } />
66â†’      </Routes>
67â†’    </Router>
68â†’  );
69â†’}
70â†’
71â†’export default App;
